{
  "version": "1.0",
  "purpose": "Step-by-step plan to solve multi-hop factual QA and output a single concise factual answer.",
  "inputs": {
    "question": "",
    "additional_context": "",
    "allow_external_knowledge": true,
    "time_reference": "",
    "geographic_scope_hint": ""
  },
  "steps": [
    {
      "id": 1,
      "module": "16: Identify the core ask",
      "goal": "Restate the question, define scope and required answer type, and list key entities/relations.",
      "actions": [
        "Restate the question in one sentence including scope (time, place, entity type).",
        "Specify the answer type needed (e.g., person, organization, date, number, title, short_phrase).",
        "List key entities and relations explicitly mentioned or implied."
      ],
      "fields": {
        "restated_question": "",
        "scope": {
          "timeframe": "",
          "location": "",
          "entity_type": ""
        },
        "answer_type": "",
        "key_entities": [],
        "key_relations": []
      },
      "checks": [
        "The restated question is unambiguous and self-contained.",
        "The answer_type is specific and aligns with the question.",
        "Key entities include aliases if present in the question."
      ]
    },
    {
      "id": 2,
      "module": "20: Gather relevant facts",
      "goal": "Extract all relevant facts from the prompt/context; prepare aliases; add only high-confidence external facts if allowed.",
      "actions": [
        "Extract facts from the prompt tied to key entities with qualifiers (dates, roles, locations).",
        "Map synonyms/aliases and variant spellings for entities.",
        "If external knowledge is allowed, add only well-known, high-confidence facts; flag any uncertainty."
      ],
      "fields": {
        "prompt_facts": [],
        "aliases": {},
        "external_facts": [],
        "uncertainty_flags": []
      },
      "checks": [
        "Each fact lists source (prompt/external) and qualifiers.",
        "External facts are widely accepted and not time-sensitive unless timeframe is clear."
      ]
    },
    {
      "id": 3,
      "module": "9: Decompose into hops",
      "goal": "Define the minimal chain of sub-questions connecting known entities to the target answer.",
      "actions": [
        "Break the problem into the fewest sub-questions needed to reach the answer.",
        "Sketch a simple chain/graph from starting entity(ies) to target.",
        "Discard branches not required to reach the target."
      ],
      "fields": {
        "sub_questions": [],
        "chain": {
          "nodes": [],
          "edges": []
        },
        "discarded_branches": []
      },
      "checks": [
        "The chain leads directly to an entity/value of the specified answer_type.",
        "Each sub_question depends on outputs from prior steps without leaps."
      ]
    },
    {
      "id": 4,
      "module": "38: Execute step by step",
      "goal": "Answer each sub-question in order using cited facts; stop when the target is reached.",
      "actions": [
        "Answer sub-questions sequentially using prompt facts first, then permitted external facts.",
        "After each hop, verify it logically feeds the next.",
        "Stop once the target is obtained; avoid extra hops."
      ],
      "fields": {
        "hop_results": [
          {
            "sub_question": "",
            "used_evidence": {
              "prompt_fact_indices": [],
              "external_fact_indices": []
            },
            "intermediate_answer": "",
            "feeds_next_hop": true
          }
        ],
        "stop_condition_met": false
      ],
      "checks": [
        "Each intermediate_answer matches the expected type for the next hop.",
        "Evidence is explicitly linked at each hop."
      ]
    },
    {
      "id": 5,
      "module": "4: Simplify and normalize",
      "goal": "Clean and standardize entities, dates, and phrasing; resolve coreference.",
      "actions": [
        "Remove details not affecting the chain of reasoning.",
        "Normalize entity names/aliases; standardize dates/units.",
        "Resolve pronouns and ambiguous references."
      ],
      "fields": {
        "normalized_entities": {},
        "normalized_dates": {},
        "clean_chain_summary": "",
        "resolved_coreference": {}
      },
      "checks": [
        "Dates use ISO format (YYYY-MM-DD when available; else YYYY-MM).",
        "Entity names are canonical and consistent across steps."
      ]
    },
    {
      "id": 6,
      "module": "10: Critically verify",
      "goal": "Detect ambiguity, conflicts, or timeframe mismatches; ensure sufficiency of evidence.",
      "actions": [
        "Check for ambiguity or conflicting facts at each hop.",
        "Confirm timeframe alignment between facts and the question.",
        "Consider alternative interpretations and whether they change the answer."
      ],
      "fields": {
        "ambiguities": [],
        "conflicts": [],
        "timeframe_checks": [],
        "alternative_interpretations": [],
        "sufficiency_of_evidence": "",
        "confidence": ""
      },
      "decision_rules": [
        "If conflicts remain unresolved or evidence is insufficient, do not guess; prepare an indeterminate output.",
        "If multiple candidates exist, choose the one that satisfies all constraints (scope, timeframe, type)."
      ]
    },
    {
      "id": 7,
      "module": "33: Produce the expected output",
      "goal": "Return a single concise factual answer with exact spelling, or state indeterminate clearly.",
      "actions": [
        "Select the single best answer consistent with constraints.",
        "Format the answer as a minimal string (name/date/number/short phrase).",
        "If indeterminate from given info, say so explicitly."
      ],
      "fields": {
        "final_answer": "",
        "answer_type": "",
        "indeterminate_reason": ""
      },
      "constraints": [
        "Do not include reasoning or extra text.",
        "No qualifiers unless required by the question.",
        "If the question expects a date/number, provide only that value in normalized format."
      ]
    }
  ],
  "normalization_guidelines": {
    "dates": "Use ISO: YYYY-MM-DD if day known; else YYYY-MM; else YYYY.",
    "names": "Use canonical full names; remove disambiguators unless required (e.g., Jr., Sr., III if part of canonical name).",
    "numbers_units": "Use numeric values with SI units if asked; otherwise match the question’s unit; spell out large integers only if requested.",
    "aliases": "Map all aliases to a canonical key; maintain alias->canonical dictionary.",
    "disambiguation": "Prefer entities matching scope (time/place/role) stated in the question."
  },
  "external_knowledge_policy": {
    "allowed": "Use only well-known, high-confidence facts (e.g., widely documented public knowledge).",
    "not_allowed": "Do not rely on obscure or contested facts; flag uncertainty if used.",
    "citation_note": "Mark items in external_facts with brief provenance (e.g., 'well-known biography', 'official record')."
  },
  "provenance_and_quality": {
    "record_evidence": "Index facts used per hop; keep prompt vs external separate.",
    "quality_flags": [
      "low_evidence",
      "timeframe_mismatch",
      "alias_confusion",
      "multiple_candidates"
    ]
  },
  "outputs": {
    "final_answer": "",
    "confidence": "",
    "provenance_summary": {
      "prompt_fact_indices_used": [],
      "external_fact_indices_used": []
    }
  }
}

